/**
 * Tier-7 Base Mini Apps — scaffolding for apps that run inside the Base App and
 * Farcaster (the Farcaster Mini Apps spec; MiniKit/OnchainKit on the Base side).
 * Pure generation/validation — no network, no keys. 0 ChainGPT credits.
 */
const PRIMARY_CATEGORIES = [
    'games', 'social', 'finance', 'utility', 'productivity',
    'health-fitness', 'news-media', 'music', 'shopping', 'education',
    'developer-tools', 'entertainment', 'art-creativity',
];
export const miniappTools = [
    {
        name: 'chaingpt_miniapp_manifest',
        description: 'Generate a Base / Farcaster Mini App manifest (`/.well-known/farcaster.json`). Produces the `miniapp` object ' +
            '(name, homeUrl, icon/splash, discovery metadata) ready to host at your domain root. Note: the ' +
            '`accountAssociation` (domain-ownership proof) must be generated by signing with your Farcaster custody key ' +
            '(via the OnchainKit CLI / Warpcast) — this tool emits a placeholder and tells you how. No network. 0 credits.',
        inputSchema: {
            type: 'object',
            properties: {
                name: { type: 'string', description: 'App name (≤32 chars).' },
                homeUrl: { type: 'string', description: 'HTTPS URL the app loads (≤1024).' },
                iconUrl: { type: 'string', description: '1024×1024 PNG icon URL (no alpha).' },
                splashImageUrl: { type: 'string', description: 'Splash image URL (200×200 recommended).' },
                splashBackgroundColor: { type: 'string', description: 'Hex color for splash bg (e.g. "#0052FF").' },
                description: { type: 'string', description: 'Full description for the app directory.' },
                subtitle: { type: 'string', description: 'Short subtitle (≤30 chars).' },
                tagline: { type: 'string', description: 'Marketing tagline (≤30 chars).' },
                primaryCategory: { type: 'string', description: `One of: ${PRIMARY_CATEGORIES.join(', ')}.` },
                tags: { type: 'array', items: { type: 'string' }, description: 'Up to 5 search tags.' },
                webhookUrl: { type: 'string', description: 'Optional webhook URL for notifications.' },
                heroImageUrl: { type: 'string', description: 'Optional 1200×630 promo image.' },
                requiredChains: { type: 'array', items: { type: 'string' }, description: 'CAIP-2 chain ids, e.g. ["eip155:8453"].' },
            },
            required: ['name', 'homeUrl', 'iconUrl'],
        },
    },
    {
        name: 'chaingpt_miniapp_embed',
        description: 'Generate the `fc:miniapp` HTML <meta> tag that turns a page into a shareable Mini App embed (rich card with a ' +
            'launch button) in the Base App / Farcaster feed. Also emits the legacy `fc:frame` tag for backward compat. ' +
            'No network. 0 ChainGPT credits.',
        inputSchema: {
            type: 'object',
            properties: {
                imageUrl: { type: 'string', description: 'Embed image URL (3:2 aspect, ≤1024px).' },
                buttonTitle: { type: 'string', description: 'Launch button text (≤32 chars).' },
                appName: { type: 'string', description: 'App name shown on the splash.' },
                appUrl: { type: 'string', description: 'URL the button launches.' },
                splashImageUrl: { type: 'string', description: 'Splash image URL.' },
                splashBackgroundColor: { type: 'string', description: 'Splash bg hex color.' },
            },
            required: ['imageUrl', 'buttonTitle', 'appUrl'],
        },
    },
    {
        name: 'chaingpt_miniapp_validate',
        description: 'Validate a Mini App manifest JSON (the `miniapp`/`frame` object or a full farcaster.json) against the spec: ' +
            'required fields, length limits, https URLs, valid category. Returns errors + warnings. No network. 0 credits.',
        inputSchema: {
            type: 'object',
            properties: {
                manifest: { type: 'object', description: 'The manifest object to validate (farcaster.json contents, or just the miniapp object).' },
            },
            required: ['manifest'],
        },
    },
];
function isHttps(u) {
    return typeof u === 'string' && /^https:\/\//.test(u);
}
function buildManifest(args) {
    const miniapp = {
        version: '1',
        name: String(args.name).slice(0, 32),
        homeUrl: String(args.homeUrl),
        iconUrl: String(args.iconUrl),
    };
    if (args.splashImageUrl)
        miniapp.splashImageUrl = String(args.splashImageUrl);
    if (args.splashBackgroundColor)
        miniapp.splashBackgroundColor = String(args.splashBackgroundColor);
    if (args.subtitle)
        miniapp.subtitle = String(args.subtitle).slice(0, 30);
    if (args.description)
        miniapp.description = String(args.description);
    if (args.tagline)
        miniapp.tagline = String(args.tagline).slice(0, 30);
    if (args.primaryCategory)
        miniapp.primaryCategory = String(args.primaryCategory);
    if (Array.isArray(args.tags))
        miniapp.tags = args.tags.slice(0, 5).map(String);
    if (args.webhookUrl)
        miniapp.webhookUrl = String(args.webhookUrl);
    if (args.heroImageUrl)
        miniapp.heroImageUrl = String(args.heroImageUrl);
    if (Array.isArray(args.requiredChains))
        miniapp.requiredChains = args.requiredChains.map(String);
    return {
        accountAssociation: {
            header: '<BASE64_HEADER>',
            payload: '<BASE64_PAYLOAD>',
            signature: '<BASE64_SIGNATURE>',
        },
        miniapp,
        // `frame` is the legacy alias hosts still read; mirror it for compatibility.
        frame: miniapp,
    };
}
function handleManifest(args) {
    const manifest = buildManifest(args);
    const warnings = [];
    if (!isHttps(args.iconUrl))
        warnings.push('iconUrl should be an https URL to a 1024×1024 PNG (no alpha).');
    if (args.primaryCategory && !PRIMARY_CATEGORIES.includes(String(args.primaryCategory))) {
        warnings.push(`primaryCategory "${args.primaryCategory}" is not a known category.`);
    }
    return [
        `=== Mini App manifest — host at https://<your-domain>/.well-known/farcaster.json ===`,
        JSON.stringify(manifest, null, 2),
        ``,
        `⚠ accountAssociation is a PLACEHOLDER. Generate the real domain-ownership signature with:`,
        `   npx create-onchain --manifest   (or the Mini App manifest tool in Warpcast settings)`,
        `   It signs your domain with your Farcaster custody key and fills header/payload/signature.`,
        warnings.length ? `\nWarnings:\n${warnings.map((w) => '  - ' + w).join('\n')}` : '',
    ].filter(Boolean).join('\n');
}
function handleEmbed(args) {
    const embed = {
        version: '1',
        imageUrl: String(args.imageUrl),
        button: {
            title: String(args.buttonTitle).slice(0, 32),
            action: {
                type: 'launch_frame',
                url: String(args.appUrl),
                name: args.appName ? String(args.appName) : undefined,
                splashImageUrl: args.splashImageUrl ? String(args.splashImageUrl) : undefined,
                splashBackgroundColor: args.splashBackgroundColor ? String(args.splashBackgroundColor) : undefined,
            },
        },
    };
    const json = JSON.stringify(embed);
    const esc = json.replace(/"/g, '&quot;');
    return [
        `=== Mini App embed meta tags — put in your page <head> ===`,
        `<meta name="fc:miniapp" content="${esc}" />`,
        `<!-- legacy fallback (older clients): -->`,
        `<meta name="fc:frame" content="${esc}" />`,
        ``,
        `Readable embed object:`,
        JSON.stringify(embed, null, 2),
    ].join('\n');
}
function handleValidate(args) {
    const m = args.manifest ?? {};
    // Accept either a full farcaster.json or just the miniapp/frame object.
    const app = m.miniapp ?? m.frame ?? m;
    const errors = [];
    const warnings = [];
    if (app.version !== '1')
        errors.push('version must be the string "1".');
    if (!app.name)
        errors.push('name is required.');
    else if (String(app.name).length > 32)
        errors.push('name exceeds 32 chars.');
    if (!app.homeUrl)
        errors.push('homeUrl is required.');
    else if (!isHttps(app.homeUrl))
        errors.push('homeUrl must be https.');
    else if (String(app.homeUrl).length > 1024)
        errors.push('homeUrl exceeds 1024 chars.');
    if (!app.iconUrl)
        errors.push('iconUrl is required.');
    else if (!isHttps(app.iconUrl))
        errors.push('iconUrl must be https.');
    if (app.splashImageUrl && !isHttps(app.splashImageUrl))
        warnings.push('splashImageUrl should be https.');
    if (app.primaryCategory && !PRIMARY_CATEGORIES.includes(String(app.primaryCategory)))
        warnings.push(`primaryCategory "${app.primaryCategory}" is not a known category.`);
    if (app.subtitle && String(app.subtitle).length > 30)
        warnings.push('subtitle should be ≤30 chars.');
    if (Array.isArray(app.tags) && app.tags.length > 5)
        warnings.push('tags should be ≤5.');
    if (m.miniapp && !m.accountAssociation)
        warnings.push('No accountAssociation — required for the app to be claimable/verified (sign your domain).');
    const ok = errors.length === 0;
    return [
        `=== Mini App manifest validation: ${ok ? 'VALID ✅' : 'INVALID ❌'} ===`,
        errors.length ? `Errors:\n${errors.map((e) => '  ✗ ' + e).join('\n')}` : '',
        warnings.length ? `Warnings:\n${warnings.map((w) => '  ⚠ ' + w).join('\n')}` : '',
        ok && !warnings.length ? 'No issues found.' : '',
    ].filter(Boolean).join('\n');
}
export async function handleMiniappTool(name, args) {
    let text;
    const a = args ?? {};
    try {
        if (name === 'chaingpt_miniapp_manifest')
            text = handleManifest(a);
        else if (name === 'chaingpt_miniapp_embed')
            text = handleEmbed(a);
        else if (name === 'chaingpt_miniapp_validate')
            text = handleValidate(a);
        else
            throw new Error(`Unknown Mini App tool: ${name}`);
    }
    catch (e) {
        text = `Error in ${name}: ${e?.message ?? e}`;
    }
    return { content: [{ type: 'text', text }] };
}
